"use client";

import { ScrollArea as ScrollAreaPrimitive } from "@base-ui/react/scroll-area";
import * as stylex from "@stylexjs/stylex";
import type React from "react";
import { scrollAreaStyles } from "./scroll-area.styles";

type ScrollAreaProps = ScrollAreaPrimitive.Root.Props & {
	scrollFade?: boolean;
	scrollbarGutter?: boolean;
	fill?: boolean;
	style?: stylex.StyleXStyles;
};

export function ScrollArea({
	children,
	className,
	scrollFade = false,
	scrollbarGutter = false,
	fill = false,
	style,
	...props
}: ScrollAreaProps): React.ReactElement {
	const rootProps = stylex.props(scrollAreaStyles.root, style as never);
	return (
		<ScrollAreaPrimitive.Root
			className={[rootProps.className, className].filter(Boolean).join(" ")}
			data-slot="scroll-area-root"
			{...props}
		>
			<ScrollAreaPrimitive.Viewport
				className={
					stylex.props(
						scrollAreaStyles.viewport,
						scrollFade && scrollAreaStyles.viewportFade,
						scrollbarGutter && scrollAreaStyles.viewportGutter,
					).className
				}
				data-slot="scroll-area-viewport"
			>
				<ScrollAreaPrimitive.Content
					className={
						stylex.props(fill && scrollAreaStyles.contentFill).className
					}
					data-slot="scroll-area-content"
				>
					{children}
				</ScrollAreaPrimitive.Content>
			</ScrollAreaPrimitive.Viewport>
			<ScrollBar orientation="vertical" />
			<ScrollBar orientation="horizontal" />
			<ScrollAreaPrimitive.Corner data-slot="scroll-area-corner" />
		</ScrollAreaPrimitive.Root>
	);
}

type ScrollBarProps = Omit<ScrollAreaPrimitive.Scrollbar.Props, "style"> & {
	style?: stylex.StyleXStyles;
};

export function ScrollBar({
	className,
	orientation = "vertical",
	style,
	...props
}: ScrollBarProps): React.ReactElement {
	const scrollbarProps = stylex.props(
		scrollAreaStyles.scrollbar,
		orientation === "horizontal" && scrollAreaStyles.scrollbarHorizontal,
		orientation === "vertical" && scrollAreaStyles.scrollbarVertical,
		style,
	);
	return (
		<ScrollAreaPrimitive.Scrollbar
			className={[scrollbarProps.className, className]
				.filter(Boolean)
				.join(" ")}
			data-slot="scroll-area-scrollbar"
			orientation={orientation}
			{...props}
		>
			<ScrollAreaPrimitive.Thumb
				className={stylex.props(scrollAreaStyles.thumb).className}
				data-slot="scroll-area-thumb"
			/>
		</ScrollAreaPrimitive.Scrollbar>
	);
}

export { ScrollAreaPrimitive };

import * as stylex from "@stylexjs/stylex";
import { theme } from "@/lib/theme/contract.stylex";
import { spacing } from "@/lib/theme/tokens.stylex";

export const scrollAreaStyles = stylex.create({
	root: {
		height: "100%",
		minHeight: 0,
		boxSizing: "border-box",
	},
	viewport: {
		height: "100%",
		borderRadius: theme.borderRadius,
		outline: "none",
		boxSizing: "border-box",
		overscrollBehaviorY: "contain",
		overscrollBehaviorX: "contain",
		":focus-visible": {
			boxShadow: `0 0 0 2px ${theme.borderStrong}`,
		},
	},
	viewportFade: {
		"--fade-size": "1.5rem",
		WebkitMaskImage:
			"linear-gradient(to bottom, transparent, black var(--fade-size), black calc(100% - var(--fade-size)), transparent)",
		maskImage:
			"linear-gradient(to bottom, transparent, black var(--fade-size), black calc(100% - var(--fade-size)), transparent)",
	},
	viewportGutter: {
		paddingRight: spacing.small,
		paddingBottom: spacing.small,
	},
	contentFill: {
		height: "100%",
		width: "100%",
	},
	scrollbar: {
		margin: spacing.xsmall,
		display: "flex",
		opacity: 0,
		boxSizing: "border-box",
		transitionProperty: "opacity",
		transitionDuration: "300ms",
		transitionTimingFunction: "ease",
		"[data-hovering]": {
			opacity: 1,
			transitionDelay: "0ms",
			transitionDuration: "100ms",
		},
		"[data-scrolling]": {
			opacity: 1,
			transitionDelay: "0ms",
			transitionDuration: "100ms",
		},
	},
	scrollbarHorizontal: {
		height: "6px",
		flexDirection: "column",
	},
	scrollbarVertical: {
		width: "6px",
	},
	thumb: {
		position: "relative",
		flexGrow: 1,
		borderRadius: theme.borderRadius,
		backgroundColor: "rgba(0, 0, 0, 0.2)",
	},
});
